      "pageId": "dashboard-page",
      "name": "首页",
      "route": "pages/Dashboard",
      "tabId": "tab-dashboard",
      "semanticTargets": [
        {
          "id": "dashboard-add-safety-button",
          "role": "action",
          "event": "navigate-to-add-safety"
        },
        {
          "id": "dashboard-start-patrol-button",
          "role": "action",
          "event": "navigate-to-patrol"
        },
        {
          "id": "dashboard-report-hazard-button",
          "role": "action",
          "event": "navigate-to-add-hazard"
        },
        {
          "id": "dashboard-view-rectify-button",
          "role": "action",
          "event": "navigate-to-rectify"
        },
        {
          "id": "dashboard-today-todo-count",
          "role": "assertion",
          "binding": "/dashboard/todayTodoCount"
        },
        {
          "id": "dashboard-hazard-count",
          "role": "assertion",
          "binding": "/dashboard/hazardCount"
        },
        {
          "id": "dashboard-rectify-rate",
          "role": "assertion",
          "binding": "/dashboard/rectifyRate"
        },
        {
          "id": "dashboard-patrol-rate",
          "role": "assertion",
          "binding": "/dashboard/patrolRate"
        },
        {
          "id": "dashboard-recent-safety-list",
          "role": "list",
          "binding": "/dashboard/recentSafetyItems",
          "itemIdPattern": "dashboard-safety-item-{id}",
          "emptyStateId": "dashboard-recent-empty"
        }
      ]
    },
    {
      "id": "safety-page",
      "surfaceId": "safety",
      "pageId": "safety-page",
      "name": "安全事项",
      "route": "pages/Safety",
      "tabId": "tab-safety",
      "semanticTargets": [
        {
          "id": "safety-add-button",
          "role": "action",
          "event": "open-add-safety-sheet"
        },
        {
          "id": "safety-filter-segment",
          "role": "input",
          "event": "change-safety-filter"
        },
        {
          "id": "safety-item-list",
          "role": "list",
          "binding": "/safety/items",
          "itemIdPattern": "safety-item-{id}",
          "emptyStateId": "safety-empty-state"
        },
        {
          "id": "safety-search-input",
          "role": "input",
          "event": "search-safety"
        }
      ]
    },
