        {
          "id": "safety-detail-title-input",
          "role": "input",
          "binding": "/safety/detail/title"
        },
        {
          "id": "safety-detail-level-picker",
          "role": "input",
          "binding": "/safety/detail/level"
        },
        {
          "id": "safety-detail-owner-input",
          "role": "input",
          "binding": "/safety/detail/owner"
