          "event": "navigate-to-create-patrol"
        },
        {
          "id": "patrol-task-list",
          "role": "list",
          "binding": "/patrol/tasks",
          "itemIdPattern": "patrol-task-{id}",
          "emptyStateId": "patrol-empty-state"
        },
        {
          "id": "patrol-active-checkin-button",
          "role": "action",
          "event": "checkin-patrol-point"
        }
      ]
    },
